 1→import React from 'react';
 2→import { View } from 'react-native';
 3→import type {
 4→  SDUIScreen,
 5→  SDUIComponent,
 6→  SDUIComponentRegistry,
 7→  SDUIComponentProps,
 8→  SDUIContext,
 9→} from '../models';
10→import { interpolateDeep } from '../utils/interpolation';
11→import { getDefaultRegistry, getRenderer } from '../registry';
12→import FallbackComponent from './FallbackComponent';
13→
14→interface ScreenRendererProps {
15→  screen: SDUIScreen;
16→  registry?: SDUIComponentRegistry;
17→  onAction?: (action: string, payload?: Record<string, unknown>) => void;
18→}
19→
20→function renderComponent(
21→  component: SDUIComponent,
22→  context: SDUIContext,
23→  registry: SDUIComponentRegistry,
24→  index: number,
25→) {
26→  const interpolatedProps = interpolateDeep(
27→    component.props,
28→    context,
29→  ) as SDUIComponentProps;
30→
31→  const Renderer = getRenderer(registry, component.type);
32→
33→  if (!Renderer) {
34→    return (
35→      <FallbackComponent
36→        key={`fallback-${index}`}
37→        type={component.type}
38→        props={interpolatedProps}
39→        context={context}
40→      />
41→    );
42→  }
43→
44→  return <Renderer key={`${component.type}-${index}`} props={interpolatedProps} context={context} />;
45→}
46→
47→export default function ScreenRenderer({
48→  screen,
49→  registry,
50→}: ScreenRendererProps) {
51→  const activeRegistry = registry ?? getDefaultRegistry();
52→  const { context, header, body, footer } = screen;
53→
54→  return (
55→    <View style={{ flex: 1 }}>
56→      {header && (
57→        <View>
58→          {renderComponent(header, context, activeRegistry, -1)}
59→        </View>
60→      )}
61→
62→      <View style={{ flex: 1 }}>
63→        {body.map((component, index) =>
64→          renderComponent(component, context, activeRegistry, index),
65→        )}
66→      </View>
67→
68→      {footer && (
69→        <View>
70→          {renderComponent(footer, context, activeRegistry, -2)}
71→        </View>
72→      )}
73→    </View>
74→  );
75→}
